package com.google.gson.internal;
import java.util.List;
import com.google.gson.ReflectionAccessFilter;
import com.google.gson.ReflectionAccessFilter.FilterResult;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Method;
import java.lang.reflect.Field;
import java.lang.reflect.AccessibleObject;

class ReflectionAccessFilterHelperTest {

  @Test
  void testIsAndroidType_withAndroidClassName() throws Exception {
    // Use reflection to access private static method isAndroidType(String)
    var method = ReflectionAccessFilterHelper.class.getDeclaredMethod("isAndroidType", String.class);
    method.setAccessible(true);
    // Android class name example
    String androidClassName = "android.app.Activity";
    boolean result = (boolean) method.invoke(null, androidClassName);
    assertTrue(result);
  }

  @Test
  void testIsAndroidType_withNonAndroidClassName() throws Exception {
    var method = ReflectionAccessFilterHelper.class.getDeclaredMethod("isAndroidType", String.class);
    method.setAccessible(true);
    String nonAndroidClassName = "java.lang.String";
    boolean result = (boolean) method.invoke(null, nonAndroidClassName);
    assertFalse(result);
  }

  @Test
  void testIsAndroidType_withNullClassName() throws Exception {
    var method = ReflectionAccessFilterHelper.class.getDeclaredMethod("isAndroidType", String.class);
    method.setAccessible(true);
    boolean result = (boolean) method.invoke(null, (Object) null);
    assertFalse(result);
  }

  @Test
  void testIsAndroidType_withClass() {
    // android class example, using a dummy android class name to simulate
    Class<?> androidClass = android.app.Activity.class;
    assertTrue(ReflectionAccessFilterHelper.isAndroidType(androidClass));
  }

  @Test
  void testIsAndroidType_withNonAndroidClass() {
    Class<?> nonAndroidClass = String.class;
    assertFalse(ReflectionAccessFilterHelper.isAndroidType(nonAndroidClass));
  }
}
